// -------------------------------------------------------
// 【設定・準備】
// -------------------------------------------------------
// 前段のノードからデータを一括取得します。
// ★重要：元データとして「Limit Items」ではなく「Filter Keywords」を使います。
// これにより、除外された記事による順序ズレ（Index Misalignment）を完全に防げます。
const filteredItems = $('Filter Keywords').all();   // フィルタ通過済みの元記事データ
const aiAgentItems  = $('Rewrite Article').all();   // AI: 記事書き換えの結果
const locationItems = $('Extract Location').all();  // AI: 場所抽出の結果

// -------------------------------------------------------
// 【メイン処理】
// 現在の入力（Translate Content）をループ処理します
// -------------------------------------------------------
return $input.all().map((item, index) => {
  try {
    // 1. インデックスを使った安全なデータの紐付け
    // ---------------------------------------------------
    // すべての処理は「Filter Keywords」を通過したリストに対して順に行われているため、
    // index番号は完全に一致します。
    const originalData = filteredItems[index].json;

    // AI抽出データがない場合のフォールバック（念のため）
    const locationName = locationItems[index]?.json?.output || "N/A";
    const rewriteTextRaw = aiAgentItems[index]?.json?.output || "";


    // 2. 翻訳データ（JSON）のパース処理
    // ---------------------------------------------------
    // Translate Contentノードからの出力（翻訳JSON）を取得
    const translationRaw = item.json.output || "{}";

    // デフォルト値の設定
    let translations = { en: "Translation Error", zh: "Translation Error", ko: "Translation Error" };

    try {
      // 生成AIが Markdown記号（```json ... ```）を付けてくることがあるため削除します
      const cleanJsonStr = translationRaw.replace(/```json|```/g, '').trim();
      translations = JSON.parse(cleanJsonStr);
    } catch (e) {
      console.log("Translation JSON Parse Error: ", e);
      // エラー時はそのままテキストを入れるなど、柔軟に対応可能です
    }


    // 3. 記事本文の整形（Markdown記号の削除）
    // ---------------------------------------------------
    // Google SheetsやSlackで見やすくするため、Markdownの見出し(#)や強調(*)を削除
    const cleanBody = rewriteTextRaw
      .replace(/[#*]/g, '')     // # と * を削除
      .replace(/\n{3,}/g, '\n\n') // 3つ以上の連続改行を2つに詰める
      .trim();


    // 4. 要約（サマリー）の抽出
    // ---------------------------------------------------
    // 「Rewrite Article」が生成した【要点サマリー】の部分だけを抜き出します
    let summary = "";
    const summaryMatch = rewriteTextRaw.match(/(?:【要点サマリー】|【Key Points Summary】|【Summary】)([\s\S]*?)(?=【|$)/);

    if (summaryMatch && summaryMatch[1]) {
      // 箇条書き記号や余計な改行を整理して、1行の文章にします
      summary = summaryMatch[1]
        .replace(/[・-]/g, '')
        .replace(/\n/g, ' ')
        .trim();
    } else {
      // 万が一抽出できない場合は、記事の冒頭120文字を使用
      summary = cleanBody.substring(0, 120) + "...";
    }


    // 5. データの結合と出力
    // ---------------------------------------------------
    // 扱いやすい1つのJSONオブジェクトにまとめます
    return {
      json: {
        title:          originalData.title,    // 元記事のタイトル (RSS由来)
        url:            originalData.link,     // 元記事のURL (RSS由来)
        location:       locationName,          // 抽出した場所
        short_summary:  summary,               // 生成した短い要約
        original_clean: cleanBody,             // 読みやすく整形した日本語記事全文

        // 翻訳データを展開
        en: translations.en,
        zh: translations.zh,
        ko: translations.ko
      },
      // ノード実行のペアリング情報を維持
      pairedItem: item.pairedItem
    };

  } catch (error) {
    // エラーハンドリング: 何か失敗してもワークフローを止めずエラーを出力
    return {
      json: {
        error: "Data Formatting Failed",
        message: error.message,
        original_title: filteredItems[index]?.json?.title || "Unknown"
      }
    };
  }
});
